						array(
							'order_id'              => $order_id,
							'is_pay_for_order_page' => $is_pay_for_order_page,
						)
					);
				} elseif ( isset( WC()->cart ) && $this->allowed_for_cart() ) {
					WC()->cart->calculate_totals();
					$payment_request = $this->build_payment_request( WC()->cart->total );
				}

				break;
		}

		return $payment_request;
	}

